class SecureLogger:
    def __init__(self, log_directory, max_log_size=10*1024*1024):
        self.log_directory = Path(log_directory)
        self.log_directory.mkdir(parents=True, exist_ok=True)
        self.max_log_size = max_log_size
        self.lock = Lock()
        self.allowed_levels = {'DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL'}
        self.allowed_services = set()
        self.api_keys = {}
        
    def register_service(self, service_name, api_key):
        if not re.match(r'^[a-zA-Z0-9_-]{3,50}$', service_name):
            raise ValueError("Invalid service name format")
        self.allowed_services.add(service_name)
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        self.api_keys[service_name] = key_hash
    
    def verify_api_key(self, service_name, api_key):
        if service_name not in self.api_keys:
            return False
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        return hmac.compare_digest(self.api_keys[service_name], key_hash)
    
    def sanitize_input(self, text, max_length=1000):
        if not isinstance(text, str):
            text = str(text)
        
        text = text[:max_length]
        text = re.sub(r'[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F]', '', text)
        text = text.replace('\n', ' ').replace('\r', ' ')
        text = re.sub(r'\s+', ' ', text)
        
        return text.strip()
    
    def sanitize_service_name(self, service_name):
        if not isinstance(service_name, str):
            return "unknown"
        service_name = re.sub(r'[^a-zA-Z0-9_-]', '', service_name)
        return service_name[:50] if service_name else "unknown"
    
    def sanitize_level(self, level):
        if not isinstance(level, str):
            return "INFO"
        level = level.upper().strip()
        return level if level in self.allowed_levels else "INFO"
    
    def get_log_file_path(self, service_name):
        safe_service_name = self.sanitize_service_name(service_name)
        date_str = datetime.utcnow().strftime('%Y-%m-%d')
        return self.log_directory / f"{safe_service_name}_{date_str}.log"
    
    def rotate_if_needed(self, log_file):
        if log_file.exists() and log_file.stat().st_size > self.max_log_size:
            timestamp = datetime.utcnow().strftime('%Y%m%d_%H%M%S')
            rotated_name = f"{log_file.stem}_{timestamp}{log_file.suffix}"
            log_file.rename(log_file.parent / rotated_name)
    
    def write_log(self, service_name, level, message, metadata=None):
        if service_name not in self.allowed_services:
            raise ValueError("Service not registered")
        
        safe_service = self.sanitize_service_name(service_name)
        safe_level = self.sanitize_level(level)
        safe_message = self.sanitize_input(message, max_length=1000)
        
        timestamp = datetime.utcnow().isoformat() + 'Z'
        
        log_entry_parts = [
            f"timestamp={timestamp}",
            f"service={safe_service}",
            f"level={safe_level}",
            f"message={safe_message}"
        ]
        
        if metadata and isinstance(metadata, dict):
            for key, value in metadata.items():
                safe_key = re.sub(r'[^a-zA-Z0-9_]', '', str(key))[:50]
                if safe_key and safe_key not in ['password', 'token', 'secret', 'key', 'api_key']:
                    safe_value = self.sanitize_input(str(value), max_length=200)
                    log_entry_parts.append(f"{safe_key}={safe_value}")
        
        log_entry = " | ".join(log_entry_parts) + "\n"
        
        log_file = self.get_log_file_path(service_name)
        
        with self.lock:
            self.rotate_if_needed(log_file)
            with open(log_file, 'a', encoding='utf-8') as f:
                f.write(log_entry)
        
        return True


class LoggingHTTPHandler(BaseHTTPRequestHandler):
    logger = None
    
    def log_message(self, format, *args):
        pass
    
    def send_json_response(self, status_code, data):
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.send_header('X-Content-Type-Options', 'nosniff')
        self.send_header('X-Frame-Options', 'DENY')
        self.end_headers()
        self.wfile.write(json.dumps(data).encode('utf-8'))
    
    def do_POST(self):
        if self.path != '/log':
            self.send_json_response(404, {'error': 'Not found'})
            return
        
        content_length = self.headers.get('Content-Length')
        if not content_length:
            self.send_json_response(400, {'error': 'Content-Length required'})
            return
        
        try:
            content_length = int(content_length)
            if content_length > 10000:
                self.send_json_response(413, {'error': 'Payload too large'})
                return
        except ValueError:
            self.send_json_response(400, {'error': 'Invalid Content-Length'})
            return
        
        api_key = self.headers.get('X-API-Key')
        if not api_key:
            self.send_json_response(401, {'error': 'API key required'})
            return
        
        try:
            body = self.rfile.read(content_length).decode('utf-8')
            data = json.loads(body)
        except (json.JSONDecodeError, UnicodeDecodeError):
            self.send_json_response(400, {'error': 'Invalid JSON'})
            return
        
        service_name = data.get('service')
        level = data.get('level', 'INFO')
        message = data.get('message')
        metadata = data.get('metadata')
        
        if not service_name or not message:
            self.send_json_response(400, {'error': 'service and message required'})
            return
        
        if not self.logger.verify_api_key(service_name, api_key):
            self.send_json_response(403, {'error': 'Invalid API key'})
            return
        
        try:
            self.logger.write_log(service_name, level, message, metadata)
            self.send_json_response(200, {'status': 'logged'})
        except ValueError as e:
            self.send_json_response(403, {'error': str(e)})
        except Exception as e:
            self.send_json_response(500, {'error': 'Internal server error'})
    
    def do_GET(self):
        if self.path == '/health':
            self.send_json_response(200, {'status': 'healthy'})
        else:
            self.send_json_response(404, {'error': 'Not found'})


def create_logging_server(host='127.0.0.1', port=8080, log_directory='./logs'):
    logger = SecureLogger(log_directory)
    
    LoggingHTTPHandler.logger = logger
    
    server = HTTPServer((host, port), LoggingHTTPHandler)
    
    return server, logger


